package {groupId}.service;

import {groupId}.entity.User;
import {groupId}.mapper.UserMapper;
import {groupId}.service.impl.UserServiceImpl;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.Arrays;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class UserServiceTest {
    @Mock
    private UserMapper userMapper;

    @InjectMocks
    private UserServiceImpl userService;

    private User testUser;

    @BeforeEach
    void setUp() {
        testUser = new User();
        testUser.setId(1L);
        testUser.setUsername("testuser");
        testUser.setEmail("test@example.com");
    }

    @Test
    void findAll_returnsUserList() {
        when(userMapper.findAll()).thenReturn(Arrays.asList(testUser));
        List<User> users = userService.findAll();
        assertEquals(1, users.size());
        assertEquals("testuser", users.get(0).getUsername());
    }

    @Test
    void findById_returnsUser() {
        when(userMapper.findById(1L)).thenReturn(testUser);
        User found = userService.findById(1L);
        assertNotNull(found);
        assertEquals("testuser", found.getUsername());
    }

    @Test
    void create_insertsAndReturns() {
        when(userMapper.insert(testUser)).thenReturn(1);
        User created = userService.create(testUser);
        assertEquals("testuser", created.getUsername());
        verify(userMapper).insert(testUser);
    }

    @Test
    void deleteById_returnsTrueOnSuccess() {
        when(userMapper.deleteById(1L)).thenReturn(1);
        assertTrue(userService.deleteById(1L));
    }

    @Test
    void deleteById_returnsFalseOnNotFound() {
        when(userMapper.deleteById(99L)).thenReturn(0);
        assertFalse(userService.deleteById(99L));
    }
}

package {groupId}.controller;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
class UserApiTest {
    @Autowired
    private MockMvc mockMvc;

    @Test
    void createUser_returns200() throws Exception {
        mockMvc.perform(post("/api/users")
                .contentType(MediaType.APPLICATION_JSON)
                .content("{\"username\":\"alice\",\"email\":\"alice@example.com\"}" ))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.username").value("alice"));
    }

    @Test
    void listUsers_returnsArray() throws Exception {
        mockMvc.perform(get("/api/users"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$").isArray());
    }

    @Test
    void getUser_notFound_returns404() throws Exception {
        mockMvc.perform(get("/api/users/99999"))
                .andExpect(status().isNotFound());
    }
}
